import { useState, useContext } from "react";
import { Container, Card, Form, Button, Alert } from "react-bootstrap";
import axios from "axios";
import UserContext from "./context";

export default function Profile() {
    const { user, setUser } = useContext(UserContext);
    const [pin, setPin] = useState(user?.transactionPin || "");
    const [name, setName] = useState(user?.name || "");
    const [message, setMessage] = useState("");
    const [error, setError] = useState("");

    const handleUpdate = async (e) => {
        e.preventDefault();
        setMessage("");
        setError("");

        if (pin.length !== 4) {
            setError("PIN must be exactly 4 digits.");
            return;
        }

        try {
            const res = await axios.put("http://localhost:8080/api/users/profile-update", {
                name,
                transactionPin: pin
            });
            setUser(res.data.updatedUser);
            setMessage("Profile updated successfully!");
        } catch (err) {
            setError(err.response?.data?.message || "Failed to update profile.");
        }
    };

    if (!user) return <Container className="mt-5"><h3>Please login to view your profile.</h3></Container>;

    return (
        <Container className="mt-5 d-flex justify-content-center">
            <Card className="shadow p-4" style={{ width: "500px" }}>
                <Card.Header className="bg-dark text-white text-center">
                    <h3>Your Profile</h3>
                </Card.Header>
                <Card.Body>
                    {message && <Alert variant="success">{message}</Alert>}
                    {error && <Alert variant="danger">{error}</Alert>}

                    <Form onSubmit={handleUpdate}>
                        <Form.Group className="mb-3">
                            <Form.Label>Name</Form.Label>
                            <Form.Control
                                type="text"
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                                required
                            />
                        </Form.Group>

                        <Form.Group className="mb-3">
                            <Form.Label>Email Address</Form.Label>
                            <Form.Control type="email" value={user.email} disabled />
                            <Form.Text className="text-muted">Email cannot be changed.</Form.Text>
                        </Form.Group>

                        <Form.Group className="mb-4">
                            <Form.Label className="fw-bold">4-Digit Transaction PIN</Form.Label>
                            <Form.Control
                                type="text"
                                maxLength="4"
                                value={pin}
                                onChange={(e) => setPin(e.target.value)}
                                required
                            />
                            <Form.Text className="text-muted">Use this PIN for all deposits and withdrawals.</Form.Text>
                        </Form.Group>

                        <Button variant="primary" type="submit" className="w-100">
                            Update Profile
                        </Button>
                    </Form>
                </Card.Body>
            </Card>
        </Container>
    );
}
